const FinanceContext = createContext<FinanceContextType | undefined>(undefined);
export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(INITIAL_DATA as any);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isAppInitializing, setIsAppInitializing] = useState(true); 
  const [isSyncing, setIsSyncing] = useState(false); 
  const [syncError, setSyncError] = useState(false); 
  const [initializationTimeout, setInitializationTimeout] = useState(false); 
  const [dataLoadedFromCloud, setDataLoadedFromCloud] = useState(false);

  // Ref para evitar bucles de guardado al cargar datos de la nube
  const ignoreNextUpdate = useRef(false);
  // Ref para el estado actual (para usar en beforeunload)
  const stateRef = useRef(state);
  // Ref para evitar concurrencia en fetchUserData
  const syncInProgressRef = useRef(false);
  // Ref para throttle de visibilidad
  const lastSyncTimeRef = useRef(0);

  // CLAVES DE ALMACENAMIENTO LOCAL
  const getBackupKey = (userId: string) => `finanzas_pro_backup_${userId}`;
  const getTimestampKey = (userId: string) => `finanzas_pro_backup_${userId}_timestamp`;
  const getDirtyKey = (userId: string) => `finanzas_pro_dirty_${userId}`;

  // Mantener stateRef actualizado
  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  // PROTECCIÓN CONTRA CIERRE REPENTINO (BeforeUnload)
  useEffect(() => {
    const handleBeforeUnload = () => {
      if (session?.user?.id && !isGuest && !ignoreNextUpdate.current) {
        const now = new Date();
        // Guardado seguro en cierre
        try {
            const key = getBackupKey(session.user.id);
            const tsKey = getTimestampKey(session.user.id);
            const dirtyKey = getDirtyKey(session.user.id);

            // Usamos localStorage directo aquí por ser síncrono crítico, pero con try-catch
            localStorage.setItem(key, JSON.stringify(stateRef.current));
            localStorage.setItem(tsKey, now.getTime().toString());
            localStorage.setItem(dirtyKey, 'true');
        } catch (e) {
            // Silencioso al cerrar
        }
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [session, isGuest]);

  // Define fetchUserData as a useCallback to ensure a stable function reference
  const fetchUserData = useCallback(async (userId: string) => {
    // Evitar llamadas concurrentes
    if (syncInProgressRef.current) return;

    syncInProgressRef.current = true;
    setIsSyncing(true); 
    setSyncError(false); 

    // 1. CARGA OPTIMISTA
    const localBackup = safeGetItem(getBackupKey(userId));
    const localTimestampStr = safeGetItem(getTimestampKey(userId));
    let localState: FinanceState | null = null;
    let localTime = 0;

    if (localBackup) {
        try {
            localState = JSON.parse(localBackup);
            localTime = localTimestampStr ? parseInt(localTimestampStr) : 0;

            if (localState) {
                console.log("App: Carga Optimista desde LocalStorage.");
                ignoreNextUpdate.current = true;
                setState(prev => ({ ...INITIAL_DATA, ...localState }));
                setDataLoadedFromCloud(true); 
                setTimeout(() => { ignoreNextUpdate.current = false; }, 500);
            }
        } catch (e) {
            console.error("App: Error leyendo backup local", e);
        }
    }

    try {
      console.log(`App: Verificando nube para usuario: ${userId}`);

      const { data, error } = await withTimeout<any>(
        supabase
          .from('profiles')
          .select('state, updated_at')
          .eq('id', userId)
          .maybeSingle(), 
        15000 
      );

      if (error) throw error;

      const cloudTime = data?.updated_at ? new Date(data.updated_at).getTime() : 0;
      const isDirty = safeGetItem(getDirtyKey(userId)) === 'true';

      // 3. Resolución de Conflictos
      if (localState && (isDirty || localTime > cloudTime + 5000)) { 
          console.log("App: Conflicto -> Local tiene prioridad (Dirty o más reciente). Subiendo...");

          await withTimeout<any>(
            supabase.from('profiles').upsert({
                id: userId,
                state: localState,
                updated_at: new Date(localTime || Date.now()).toISOString()
            }), 
            15000
          );

          safeSetItem(getDirtyKey(userId), 'false');

      } else if (data && data.state && cloudTime > localTime) {
          console.log("App: Conflicto -> Nube es más reciente. Actualizando...");
          const mergedState = { ...INITIAL_DATA, ...data.state };

          ignoreNextUpdate.current = true;
          setState(mergedState as FinanceState);

          safeSetItem(getBackupKey(userId), JSON.stringify(mergedState));
          safeSetItem(getTimestampKey(userId), cloudTime.toString());
          safeSetItem(getDirtyKey(userId), 'false');

          setTimeout(() => { ignoreNextUpdate.current = false; }, 500);
      } 
      else {
          console.log("App: Sincronización verificada. Todo al día.");
      }

      setDataLoadedFromCloud(true);

    } catch (err) {
      console.warn("App: Modo Offline activado por timeout o error de red:", err);
      if (!localState) {
          setSyncError(true);
      } else {
          setSyncError(true); 
      }
    } finally {
      setIsSyncing(false);
      syncInProgressRef.current = false;
    }
  }, [setIsSyncing, setSyncError, setState, setDataLoadedFromCloud]);

  const manualRefresh = useCallback(async () => {
    if (!session || isGuest) return;
    console.log("App: Refresco manual iniciado por el usuario.");
    await fetchUserData(session.user.id);
  }, [session, isGuest, fetchUserData]);

  // RECONEXIÓN INTELIGENTE AL VOLVER A LA APP (Visibility Only - REMOVED FOCUS - THROTTLED)
  useEffect(() => {
    const handleReSync = async () => {
      const now = Date.now();
      // Throttle: Solo sincronizar si han pasado 30 segundos desde la última vez
      if (document.visibilityState === 'visible' && session?.user?.id && !isGuest && !isSyncing && !syncInProgressRef.current) {
        if (now - lastSyncTimeRef.current < 30000) return;

        console.log("App: Regreso detectado. Verificando sincronización...");
        lastSyncTimeRef.current = now;
        setTimeout(() => {
           fetchUserData(session.user.id);
        }, 500);
      }
    };

    // Eliminado 'focus' para evitar bucles en móviles al abrir teclado
    document.addEventListener('visibilitychange', handleReSync);

    return () => {
      document.removeEventListener('visibilitychange', handleReSync);
    };
  }, [session, isGuest, isSyncing, fetchUserData]);

  const loginAsGuest = useCallback(() => {
    console.log("App: Iniciando sesión como invitado.");
    safeSetItem('finanzas_pro_guest', 'true');
    setIsGuest(true);
    const saved = safeGetItem('finanzas_pro_local_state');
    if (saved) setState({ ...INITIAL_DATA, ...JSON.parse(saved) } as FinanceState);
    else setState(INITIAL_DATA as any);
    setIsAppInitializing(false); 
    setSyncError(false); 
    setInitializationTimeout(false); 
  }, [setIsGuest, setState, setIsAppInitializing, setSyncError, setInitializationTimeout]);

  const initApp = useCallback(async () => {
    setIsAppInitializing(true); 
    setSyncError(false); 
    setInitializationTimeout(false); 

    let timeoutId: number;
    // Aumentado el tiempo de espera de inicialización a 12 segundos para dar más margen a móviles
    timeoutId = window.setTimeout(() => {
        console.warn("App: Timeout inicialización prolongado. Forzando entrada con datos locales.");
        setInitializationTimeout(true); 
        setIsAppInitializing(false);
    }, 12000); 

    try {
      const { data: { session: currentSession }, error: sessionError } = await supabase.auth.getSession();

      if (sessionError) throw sessionError;

      if (currentSession) {
        setSession(currentSession);
        setIsGuest(false);
        await fetchUserData(currentSession.user.id); 
      } else {
        const guestFlag = safeGetItem('finanzas_pro_guest') === 'true';
        if (guestFlag) {
          setIsGuest(true);
          const savedState = safeGetItem('finanzas_pro_local_state');
          if (savedState) setState({ ...INITIAL_DATA, ...JSON.parse(savedState) } as FinanceState);
          setDataLoadedFromCloud(false); 
        } else {
          setSession(null); 
          setIsGuest(false);
          setDataLoadedFromCloud(false);
          setState(INITIAL_DATA as any); 
        }
      }
    } catch (err) {
      console.error("App: Error inicialización (Offline/Fetch):", err);
      setSyncError(true); 

      const guestFlag = safeGetItem('finanzas_pro_guest') === 'true';
      if (guestFlag) {
           setIsGuest(true);
           const savedState = safeGetItem('finanzas_pro_local_state');
           if (savedState) setState({ ...INITIAL_DATA, ...JSON.parse(savedState) } as FinanceState);
      }
    } finally {
      window.clearTimeout(timeoutId); 
      setIsAppInitializing(false); 
    }
  }, [fetchUserData, setSession, setIsGuest, setState, setIsAppInitializing, setSyncError, setInitializationTimeout, setDataLoadedFromCloud]);

  const saveData = useCallback(async () => {
    if (!session || isGuest) return;
    console.log("App: Guardado manual solicitado.");
    setIsSyncing(true);
    setSyncError(false);

    const now = new Date();
    // 1. Guardar en local inmediatamente (Seguro)
    safeSetItem(getBackupKey(session.user.id), JSON.stringify(state));
    safeSetItem(getTimestampKey(session.user.id), now.getTime().toString());

    try {
      // 2. Enviar a Supabase con TIMEOUT
      const { error } = await withTimeout<any>(
        supabase
          .from('profiles')
          .upsert({ 
            id: session.user.id, 
            state, 
            updated_at: now.toISOString() 
          }),
        10000 
      );

      if (error) throw error;

      // 3. Éxito
      safeSetItem(getDirtyKey(session.user.id), 'false');
      console.log("App: Guardado manual exitoso.");
    } catch (err) {
      console.warn("App: Fallo al guardar en nube (guardado en local):", err);
      setSyncError(true);
    } finally {
      setIsSyncing(false); 
    }
  }, [session, isGuest, state, setIsSyncing, setSyncError]);

  const forceResync = useCallback(async () => {
    if (!session || isGuest) return;
    console.log("App: Usuario solicitó resincronización forzada.");
    setIsSyncing(false); 
    setSyncError(false);
    setIsSyncing(true);
    try {
        await fetchUserData(session.user.id);
    } catch(e) {
        console.error("App: Resync forzado falló", e);
        setSyncError(true);
    } finally {
        setIsSyncing(false);
    }
  }, [session, isGuest, fetchUserData]);

  const retrySync = useCallback(async () => {
     await saveData();
  }, [saveData]);

  // Manejo de Sesión
  useEffect(() => {
    initApp();
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, newSession) => {
      if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') {
          if (newSession && newSession.user.id !== session?.user?.id) {
            setSession(newSession);
            setIsGuest(false);
            // Solo llamar fetch si no está ya en progreso
            if (!syncInProgressRef.current) {
                await fetchUserData(newSession.user.id);
            }
          }
      } else if (event === 'SIGNED_OUT') {
        setSession(null);
        setIsGuest(false);
        setState(INITIAL_DATA as any); 
        setDataLoadedFromCloud(false);
      }
    });
    return () => subscription.unsubscribe();
  }, [fetchUserData, initApp, setSession, setIsGuest, setState, setDataLoadedFromCloud]);

  // PERSISTENCIA ROBUSTA (Dirty Flag Pattern) CON DEBOUNCE AUMENTADO
  // Esto previene escrituras síncronas que bloquean el UI en móviles y reduce la frecuencia
  useEffect(() => {
    let debounceTimer: number;

    if (ignoreNextUpdate.current) return;

    if (!isAppInitializing) {
      // 2 Segundos de espera para guardar (Debounce Aumentado) para evitar sobrecarga en typing
      debounceTimer = window.setTimeout(async () => {
        const now = new Date();

        // A. Guardado Local (Ahora dentro del timeout para no bloquear render)
        if (session) {
           safeSetItem(getBackupKey(session.user.id), JSON.stringify(state));
           safeSetItem(getTimestampKey(session.user.id), now.getTime().toString());
           safeSetItem(getDirtyKey(session.user.id), 'true');
        } else if (isGuest) {
           safeSetItem('finanzas_pro_local_state', JSON.stringify(state));
        }

        // B. Subida a Nube (Solo si hay sesión y ya cargó la nube)
        if (session && dataLoadedFromCloud && !isGuest) {
            setIsSyncing(true);
            try {
              const { error } = await withTimeout<any>(
                 supabase
                .from('profiles')
                .upsert({ 
                  id: session.user.id, 
                  state, 
                  updated_at: now.toISOString() 
                }),
                20000 
              );

              if (error) throw error;

              safeSetItem(getDirtyKey(session.user.id), 'false');
              setSyncError(false); 
            } catch (err) {
              console.warn("App: Pendiente de sincronizar fondo:", err);
              setSyncError(true); 
            } finally {
              setIsSyncing(false); 
            }
        }
      }, 2000); // 2000ms delay
    }

    return () => {
      window.clearTimeout(debounceTimer);
    };
  }, [state, session, isGuest, isAppInitializing, dataLoadedFromCloud, setIsSyncing, setSyncError]);

  const logout = () => {
    console.log("App: Cerrando sesión.");
    localStorage.removeItem('finanzas_pro_guest');
    setIsGuest(false);
    setSession(null);
    setDataLoadedFromCloud(false);
    supabase.auth.signOut();
  };

  const getAccountHistoricalBalance = useCallback((accountId: string, dateStr: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;

    let cutoffDate = dateStr;
    if (dateStr.length === 4) { 
      cutoffDate = `${dateStr}-12-31`;
    } else if (dateStr.length === 7) { 
      const [y, m] = dateStr.split('-').map(Number);
      const lastDay = new Date(y, m, 0).getDate();
      cutoffDate = `${dateStr}-${lastDay}`;
    }

    let balance = account.initialBalance;
    const relevantTxs = state.transactions.filter(t => 
      t.accountId === accountId && t.date <= cutoffDate
    );

    for (const t of relevantTxs) {
      if (t.type === 'income') {
        balance += t.amount;
      } else {
        balance -= t.amount;
      }
    }
    return balance;
  }, [state.accounts, state.transactions]);

  const getSavingHistoricalBalance = useCallback((savingId: string, dateStr: string) => {
    const saving = state.savings.find(s => s.id === savingId);
    if (!saving) return 0;

    let cutoffDate = dateStr;
    if (dateStr.length === 4) {
      cutoffDate = `${dateStr}-12-31`;
    } else if (dateStr.length === 7) {
      const [y, m] = dateStr.split('-').map(Number);
      const lastDay = new Date(y, m, 0).getDate();
      cutoffDate = `${dateStr}-${lastDay}`;
    }

    let balance = saving.currentAmount;
    const relevantTxs = state.transactions.filter(t => 
      t.savingId === savingId && t.date <= cutoffDate
    );

    for (const t of relevantTxs) {
      if (t.type === 'expense') {
        balance += t.amount;
      } else if (t.type === 'income') {
        balance -= t.amount;
      }
    }
    return balance;
  }, [state.savings, state.transactions]);

  const getNetWorthHistorical = useCallback((dateStr: string) => {
    const accountsTotal = state.accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, dateStr), 0);
    const savingsTotal = state.savings.reduce((sum, sav) => sum + getSavingHistoricalBalance(sav.id, dateStr), 0);
    return accountsTotal + savingsTotal;
  }, [state.accounts, state.savings, getAccountHistoricalBalance, getSavingHistoricalBalance]);

  // Context Memoization para prevenir re-renders en cadena
  const contextValue = useMemo<FinanceContextType>(() => ({
    ...state,
    extraSavings: state.extraSavings || [],
    manualContributions: state.manualContributions || {},

    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, 

    isGuest,
    isSyncing,
    syncError,

    loginAsGuest,
    retrySync,
    manualRefresh,
    saveData,
    forceResync,

    addTransaction: (t, myPart) => {
      const id = 'tx_' + Math.random().toString(36).substr(2, 9);
      let finalTx = { ...t, id };
      let newRefunds = [...state.refunds];
      if (t.type === 'expense' && t.isRefund) {
        const refundId = 'ref_' + Date.now();
        const partToPay = myPart !== undefined ? myPart : t.amount / 2;
        newRefunds.push({ id: refundId, name: t.description, totalAmount: t.amount, paidByMe: partToPay, pendingAmount: t.amount - partToPay, status: 'open', notes: 'Auto', date: t.date, category: t.category, originTransactionId: id });
        finalTx.refundId = refundId;
      }
      setState(prev => ({ ...prev, transactions: [finalTx as Transaction, ...prev.transactions], refunds: newRefunds }));
    },
    updateTransaction: (updatedTx) => setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t) })),
    deleteTransaction: (id) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(tx => tx.id !== id) })),
    addAccount: (a) => setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id: 'acc_' + Date.now(), currentBalance: a.initialBalance } as Account] })),
    updateAccount: (a) => setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) })),
    deleteAccount: (id) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) })),
    addSaving: (s) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: 'sav_' + Date.now() } as Saving] })),
    updateSaving: (s) => setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) })),
    deleteSaving: (id) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) })),
    addRefund: (r) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: 'ref_' + Date.now() } as Refund] })),
    updateRefund: (r) => setState(prev => ({ ...prev, refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf) })),
    deleteRefund: (id) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) })),
    mergeRefunds: (id1, id2) => {
      const r1 = state.refunds.find(r => r.id === id1);
      const r2 = state.refunds.find(r => r.id === id2);
      if (!r1 || !r2) return;
      const merged: Refund = {
        id: 'ref_' + Date.now(),
        name: `${r1.name} + ${r2.name}`,
        totalAmount: r1.totalAmount + r2.totalAmount,
        paidByMe: r1.paidByMe + r2.paidByMe,
        pendingAmount: r1.pendingAmount + r2.pendingAmount,
        status: (r1.status === 'open' || r2.status === 'open') ? 'open' : 'closed',
        notes: `Fusionado: ${r1.notes} | ${r2.notes}`,
        date: new Date().toISOString(),
        category: r1.category
      };
      setState(prev => ({
        ...prev,
        refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
      }));
    },
    addBudget: (b) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: 'budget_' + Date.now(), spent: 0 } as Budget] })),
    updateBudget: (b) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg) })),
    deleteBudget: (id) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) })),

    // NEW METHODS FOR PERSISTENT WEALTH PROJECTION
    addExtraSaving: (e) => setState(prev => ({ ...prev, extraSavings: [...(prev.extraSavings || []), { ...e, id: 'extra_' + Date.now() } as ExtraSaving] })),
    deleteExtraSaving: (id) => setState(prev => ({ ...prev, extraSavings: (prev.extraSavings || []).filter(e => e.id !== id) })),
    updateManualContribution: (savingId, amount) => setState(prev => ({ 
      ...prev, 
      manualContributions: { ...(prev.manualContributions || {}), [savingId]: amount } 
    })),

    changePeriod: (offset) => {
      const [year, month] = state.currentDate.split('-').map(Number);
      const newDate = state.viewMode === 'year' 
        ? new Date(year + offset, 0, 1) 
        : new Date(year, (month || 1) - 1 + offset, 1); 

      const newDateStr = state.viewMode === 'year' 
        ? newDate.getFullYear().toString() 
        : `${newDate.getFullYear()}-${String(newDate.getMonth() + 1).padStart(2, '0')}`;
      setState(prev => ({ ...prev, currentDate: newDateStr }));
    },
    setPeriod: (dateStr) => setState(prev => ({ ...prev, currentDate: dateStr })),
    setViewMode: (mode) => setState(prev => ({ ...prev, viewMode: mode })),
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges })),
    toggleTheme: () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }))
  }), [state, isGuest, isSyncing, syncError, getAccountHistoricalBalance, getSavingHistoricalBalance, getNetWorthHistorical, loginAsGuest, retrySync, manualRefresh, saveData, forceResync]);

  if (isAppInitializing) { 
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
        <div className="relative mb-6">
          <div className="w-20 h-20 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div>
          <Wallet className="absolute inset-0 m-auto text-blue-600 animate-pulse" size={32} />
        </div>
        <p className="text-slate-500 font-black uppercase tracking-[0.2em] text-[10px] animate-pulse">Sincronizando Bóveda Digital...</p>
        {(syncError || initializationTimeout) && ( 
          <div className="mt-4 flex flex-col items-center gap-2 p-3 bg-amber-50 dark:bg-amber-900/20 rounded-xl border border-amber-100 dark:border-amber-900/40 animate-in fade-in zoom-in duration-300 max-w-xs text-center">
            <AlertTriangle className="text-amber-600" size={24} />
            <p className="text-amber-600 text-xs font-medium">
              Tardando más de lo esperado. <br/> Probablemente la nube no responde, pero tienes tus datos locales seguros.
            </p>
            <div className="flex gap-2 mt-2">
              <button onClick={() => window.location.reload()} className="p-2 px-4 rounded-lg bg-blue-600 text-white text-xs font-bold hover:bg-blue-700">
                Recargar
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Login onGuestLogin={loginAsGuest} />;
  }

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 overflow-hidden text-slate-900 dark:text-slate-100 font-sans">
          <Sidebar isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onLogout={logout} isGuest={isGuest} session={session} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={() => setIsMenuOpen(true)} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/wealth" element={<WealthProjections />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

