import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ShoppingBag, 
  ChevronRight, 
  X, 
  TrendingDown,
  TrendingUp,
  AlertCircle,
  Tag,
  ChevronDown,
  History,
  Palette,
  AlertTriangle
} from 'lucide-react';
import { Budget, Transaction } from '../types';
import { CATEGORIES, INCOME_CATEGORIES, ICON_MAP, BUDGET_PRESET_COLORS } from '../constants';

const BudgetManager: React.FC = () => {
  const { budgets, transactions, currentDate, updateBudget, addBudget, deleteBudget, theme } = useFinance();

  // UI States
  const [activeTab, setActiveTab] = useState<'expense' | 'income'>('expense');
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null);
  const [isEditing, setIsEditing] = useState<Budget | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [budgetToDelete, setBudgetToDelete] = useState<Budget | null>(null);

  // Form States
  const [category, setCategory] = useState('');
  const [limit, setLimit] = useState<number | ''>('');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [selectedIcon, setSelectedIcon] = useState('ShoppingBag');
  const [selectedColor, setSelectedColor] = useState('#3b82f6');

  const budgetsWithCalculatedSpent = useMemo(() => {
    return budgets.map(b => {
      const calculatedSpent = transactions
        .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
        .reduce((sum, t) => {
          if (b.type === 'expense') {
            if (t.type === 'expense') return sum + t.amount;
            if (t.type === 'income' && t.refundId) return sum - t.amount;
          }
          if (b.type === 'income' && t.type === 'income') return sum + t.amount;
          return sum;
        }, 0);
      return { ...b, spent: calculatedSpent };
    });
  }, [budgets, transactions, currentDate]);

  const filteredBudgets = useMemo(() => {
    return budgetsWithCalculatedSpent.filter(b => b.type === activeTab);
  }, [budgetsWithCalculatedSpent, activeTab]);

  const budgetTransactions = useMemo(() => {
    if (!selectedBudget) return [];
    return transactions.filter(t => 
      t.category === selectedBudget.category && 
      t.date.startsWith(currentDate)
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedBudget, transactions, currentDate]);

  const totals = useMemo(() => {
    const b = budgetsWithCalculatedSpent.filter(x => x.type === activeTab);
    return {
      limit: b.reduce((s, x) => s + x.limit, 0),
      actual: b.reduce((s, x) => s + x.spent, 0)
    };
  }, [budgetsWithCalculatedSpent, activeTab]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomMode ? customCategory : category;
    if (!finalCategory || limit === '') return;

    if (isEditing) {
      updateBudget({ 
        ...isEditing, 
        category: finalCategory, 
        limit: Number(limit), 
        icon: selectedIcon, 
        color: selectedColor 
      });
      setIsEditing(null);
    } else {
      addBudget({ 
        category: finalCategory, 
        limit: Number(limit), 
        type: activeTab,
        icon: selectedIcon,
        color: selectedColor
      });
      setIsCreating(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setCategory('');
    setLimit('');
    setCustomCategory('');
    setIsCustomMode(false);
    setSelectedIcon('ShoppingBag');
    setSelectedColor('#3b82f6');
  };

  const openCreate = () => {
    resetForm();
    const defaultCats = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    setCategory(defaultCats[0].name);
    setSelectedIcon(defaultCats[0].icon);
    setSelectedColor(defaultCats[0].color);
    setIsCreating(true);
  };

  const openEdit = (b: Budget) => {
    const defaultCats = b.type === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    const isStandard = defaultCats.some(c => c.name === b.category);
    setCategory(isStandard ? b.category : 'Otra');
    setCustomCategory(isStandard ? '' : b.category);
    setIsCustomMode(!isStandard);
    setLimit(b.limit);
    setSelectedIcon(b.icon);
    setSelectedColor(b.color || '#3b82f6');
    setIsEditing(b);
  };

  const confirmDeletion = () => {
    if (budgetToDelete) {
      deleteBudget(budgetToDelete.id);
      setBudgetToDelete(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Presupuestos</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Controla tus finanzas de {currentDate} con precisión.</p>
        </div>
        <button 
          type="button"
          onClick={openCreate}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
        >
          <Plus size={20} /> Nuevo Límite
        </button>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1.5 rounded-3xl w-full md:w-fit border border-slate-200 dark:border-slate-700 shadow-inner">
        <button type="button" onClick={() => setActiveTab('expense')} className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'expense' ? 'bg-white dark:bg-slate-700 text-rose-600 dark:text-rose-400 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}><TrendingDown size={16} /> GASTOS</button>
        <button type="button" onClick={() => setActiveTab('income')} className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'income' ? 'bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}><TrendingUp size={16} /> INGRESOS</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filteredBudgets.map(b => {
          const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
          const isOverBudget = activeTab === 'expense' && b.spent > b.limit;
          return (
            <div key={b.id} onClick={() => setSelectedBudget(b)} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all group cursor-pointer active:scale-[0.99] duration-300">
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner`} style={{ backgroundColor: `${b.color}${theme === 'dark' ? '30' : '15'}`, color: b.color }}>
                    {ICON_MAP[b.icon] ? React.cloneElement(ICON_MAP[b.icon] as React.ReactElement, { size: 24 }) : <span className="text-2xl">{b.icon || <Tag size={24} />}</span>}
                  </div>
                  <div>
                    <h4 className="text-lg font-black text-slate-800 dark:text-white tracking-tight">{b.category}</h4>
                    <p className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{activeTab === 'expense' ? 'Gasto' : 'Ingreso'}</p>
                  </div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                  <button type="button" onClick={(e) => { e.stopPropagation(); openEdit(b); }} className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/40 rounded-xl transition-colors"><Edit2 size={18} /></button>
                  <button type="button" onClick={(e) => { e.stopPropagation(); setBudgetToDelete(b); }} className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/40 rounded-xl transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
              <div className="space-y-5">
                <div className="flex justify-between items-end">
                   <div>
                      <p className={`text-4xl font-black tracking-tight ${isOverBudget ? 'text-rose-500' : 'text-slate-900 dark:text-white'}`}>{b.spent.toLocaleString()}€</p>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">de {b.limit.toLocaleString()}€</p>
                   </div>
                   <div className="text-right">
                      <span style={!isOverBudget ? { backgroundColor: `${b.color}${theme === 'dark' ? '30' : '15'}`, color: b.color } : {}} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider ${isOverBudget ? 'bg-rose-50 text-rose-500' : ''}`}>
                        {activeTab === 'expense' ? (isOverBudget ? 'Excedido' : 'Correcto') : (b.spent >= b.limit ? 'Logrado' : 'En progreso')}
                      </span>
                   </div>
                </div>
                <div className="w-full bg-slate-100 dark:bg-slate-800 h-3 rounded-full overflow-hidden">
                  <div className={`h-full rounded-full transition-all duration-1000 ease-out`} style={{ width: `${progress}%`, backgroundColor: isOverBudget ? '#f43f5e' : b.color }}></div>
                </div>
                <p className="text-xs text-slate-400 font-bold flex items-center gap-1"><ChevronRight size={14} style={{ color: b.color }} /> Ver detalles</p>
              </div>
            </div>
          );
        })}
      </div>

      {selectedBudget && (
        <div className="fixed inset-0 bg-slate-900/90 z-[60] flex items-center justify-center p-4" onClick={() => setSelectedBudget(null)}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-8 md:p-10 shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-start mb-8 flex-shrink-0">
               <div className="flex items-center gap-5">
                  <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center`} style={{ backgroundColor: `${selectedBudget.color}${theme === 'dark' ? '30' : '15'}`, color: selectedBudget.color }}>
                    {ICON_MAP[selectedBudget.icon] ? React.cloneElement(ICON_MAP[selectedBudget.icon] as React.ReactElement, { size: 28 }) : <span className="text-3xl">{selectedBudget.icon || <Tag size={28} />}</span>}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{selectedBudget.category}</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Movimientos de {currentDate}</p>
                  </div>
               </div>
               <button type="button" onClick={() => setSelectedBudget(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button>
            </div>
            <div className="bg-slate-50 dark:bg-slate-800/50 rounded-3xl p-6 mb-8 border border-slate-100 dark:border-slate-800 flex-shrink-0">
               <div className="flex justify-between items-end mb-4">
