             <button type="button" onClick={() => setViewMode('year')} className={`p-1.5 rounded-lg transition-all ${viewMode === 'year' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400'}`}><CalendarRange size={18} /></button>
          </div>
          <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl shadow-inner relative">
