import React, { createContext, useContext, useState, useEffect, useMemo } from 'react';
import { BrowserRouter as Router, Routes, Route, NavLink, Navigate } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  CreditCard, 
  PiggyBank, 
  ArrowRightLeft, 
  PieChart, 
  Bot, 
  LineChart,
  LogOut,
  Menu,
  X,
  Sun,
  Moon
} from 'lucide-react';
import { supabase } from './services/supabase';
import Dashboard from './components/Dashboard';
import Accounts from './components/Accounts';
import Transactions from './components/Transactions';
import BudgetComponent from './components/Budget';
import Savings from './components/Savings';
import Refunds from './components/Refunds';
import AIAdvisor from './components/AIAdvisor';
import WealthProjections from './components/WealthProjections';
import Login from './components/Login';
import { FinanceState, Account, Transaction, Budget, Saving, Refund, AIChallenge, ExtraSaving } from './types';
import { INITIAL_DATA } from './constants';

interface FinanceContextType extends FinanceState {
  setChallenges: (challenges: AIChallenge[]) => void;
  updateLayout: (layout: string[]) => void;
  addAccount: (account: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (account: Account) => void;
  deleteAccount: (id: string) => void;
  addTransaction: (transaction: Omit<Transaction, 'id'>, customAmount?: number) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addSaving: (saving: Omit<Saving, 'id'>) => void;
  updateSaving: (saving: Saving) => void;
  deleteSaving: (id: string) => void;
  addBudget: (budget: Omit<Budget, 'id' | 'spent'>) => void;
  updateBudget: (budget: Budget) => void;
  deleteBudget: (id: string) => void;
  addRefund: (refund: Omit<Refund, 'id'>) => void;
  updateRefund: (refund: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addExtraSaving: (extra: Omit<ExtraSaving, 'id'>) => void;
  deleteExtraSaving: (id: string) => void;
  updateManualContribution: (savingId: string, amount: number) => void;

  getAccountHistoricalBalance: (accountId: string, dateStr: string) => number;
  getSavingHistoricalBalance: (savingId: string, dateStr: string) => number;
  getNetWorthHistorical: (dateStr: string) => number;

  toggleTheme: () => void;
  logout: () => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_state');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    localStorage.setItem('finance_state', JSON.stringify(state));
    if (state.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [state]);

  const toggleTheme = () => {
    setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));
  };

  const logout = async () => {
    if (!isGuest) await supabase.auth.signOut();
    setIsGuest(false);
    setSession(null);
  };

  // Helper methods
  const getAccountHistoricalBalance = (accountId: string, dateStr: string) => {
    const account = state.accounts.find(a => a.id === accountId);
    if (!account) return 0;

    const targetDate = new Date(dateStr.length === 4 ? `${dateStr}-12-31` : `${dateStr}-01`);
    if (dateStr.length !== 4) {
        targetDate.setMonth(targetDate.getMonth() + 1);
        targetDate.setDate(0);
    }

    const relevantTx = state.transactions.filter(t => {
       const tDate = new Date(t.date);
       return tDate <= targetDate && t.accountId === accountId;
    });

    let balance = account.initialBalance;
    relevantTx.forEach(t => {
      if (t.type === 'income') balance += t.amount;
      else balance -= t.amount;
    });

    return balance;
  };

  const getSavingHistoricalBalance = (savingId: string, dateStr: string) => {
      const saving = state.savings.find(s => s.id === savingId);
      if (!saving) return 0;

      const targetDate = new Date(dateStr.length === 4 ? `${dateStr}-12-31` : `${dateStr}-01`);
      if (dateStr.length !== 4) {
          targetDate.setMonth(targetDate.getMonth() + 1);
          targetDate.setDate(0);
      }

      const relevantTx = state.transactions.filter(t => {
          const tDate = new Date(t.date);
          return tDate <= targetDate && t.savingId === savingId;
      });

      let balance = 0; 
      relevantTx.forEach(t => {
         if (t.type === 'expense') balance += t.amount;
      });

      if (dateStr === state.currentDate) return saving.currentAmount;

      return balance; 
  };

  const getNetWorthHistorical = (dateStr: string) => {
      const accBalance = state.accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, dateStr), 0);
      const savBalance = state.savings.reduce((sum, sav) => sum + getSavingHistoricalBalance(sav.id, dateStr), 0);
      return accBalance + savBalance;
  };

  // State mutators
  const updateLayout = (layout: string[]) => setState(prev => ({ ...prev, dashboardLayout: layout }));
  const setChallenges = (challenges: AIChallenge[]) => setState(prev => ({ ...prev, challenges }));

  const addAccount = (acc: Omit<Account, 'id' | 'currentBalance'>) => {
      const newAcc: Account = { ...acc, id: `acc_${Date.now()}`, currentBalance: acc.initialBalance };
      setState(prev => ({ ...prev, accounts: [...prev.accounts, newAcc] }));
  };
  const updateAccount = (acc: Account) => setState(prev => ({ ...prev, accounts: prev.accounts.map(a => a.id === acc.id ? acc : a) }));
  const deleteAccount = (id: string) => setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));

  const addTransaction = (tx: Omit<Transaction, 'id'>, customAmount?: number) => {
      const newTx: Transaction = { ...tx, id: `tx_${Date.now()}_${Math.random()}` };
      setState(prev => {
          let newAccounts = [...prev.accounts];
          let newSavings = [...prev.savings];

          const accIndex = newAccounts.findIndex(a => a.id === tx.accountId);
          if (accIndex >= 0) {
              if (tx.type === 'income') newAccounts[accIndex].currentBalance += tx.amount;
              else newAccounts[accIndex].currentBalance -= tx.amount;
          }

          if (tx.savingId) {
             const savIndex = newSavings.findIndex(s => s.id === tx.savingId);
             if (savIndex >= 0) {
                 if (tx.type === 'expense') newSavings[savIndex].currentAmount += tx.amount;
                 else newSavings[savIndex].currentAmount -= tx.amount;
             }
          }

          return { ...prev, accounts: newAccounts, savings: newSavings, transactions: [...prev.transactions, newTx] };
      });
  };

  const updateTransaction = (tx: Transaction) => {
      setState(prev => ({ ...prev, transactions: prev.transactions.map(t => t.id === tx.id ? tx : t) }));
  };
  const deleteTransaction = (id: string) => setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));

  const addSaving = (s: Omit<Saving, 'id'>) => setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id: `sav_${Date.now()}` }] }));
  const updateSaving = (s: Saving) => setState(prev => ({ ...prev, savings: prev.savings.map(sav => sav.id === s.id ? s : sav) }));
  const deleteSaving = (id: string) => setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));

  const addBudget = (b: Omit<Budget, 'id' | 'spent'>) => setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id: `budget_${Date.now()}`, spent: 0 }] }));
  const updateBudget = (b: Budget) => setState(prev => ({ ...prev, budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg) }));
  const deleteBudget = (id: string) => setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) }));

  const addRefund = (r: Omit<Refund, 'id'>) => setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id: `ref_${Date.now()}` }] }));
  const updateRefund = (r: Refund) => setState(prev => ({ ...prev, refunds: prev.refunds.map(ref => ref.id === r.id ? r : ref) }));
  const deleteRefund = (id: string) => setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) }));
  const mergeRefunds = (id1: string, id2: string) => {
     setState(prev => {
         const r1 = prev.refunds.find(r => r.id === id1);
         const r2 = prev.refunds.find(r => r.id === id2);
         if (!r1 || !r2) return prev;

         const newR: Refund = {
             ...r1,
             name: `${r1.name} + ${r2.name}`,
             totalAmount: r1.totalAmount + r2.totalAmount,
             paidByMe: r1.paidByMe + r2.paidByMe,
             pendingAmount: r1.pendingAmount + r2.pendingAmount,
             notes: `Fusionado: \n${r1.notes || ''}\n${r2.notes || ''}`
         };

         return {
             ...prev,
             refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), newR]
         };
     });
  };

  const addExtraSaving = (extra: Omit<ExtraSaving, 'id'>) => setState(prev => ({ ...prev, extraSavings: [...prev.extraSavings, { ...extra, id: `es_${Date.now()}` }] }));
  const deleteExtraSaving = (id: string) => setState(prev => ({ ...prev, extraSavings: prev.extraSavings.filter(e => e.id !== id) }));
  const updateManualContribution = (savingId: string, amount: number) => setState(prev => ({ ...prev, manualContributions: { ...prev.manualContributions, [savingId]: amount } }));

  const navItems = [
    { to: "/", icon: <LayoutDashboard size={20} />, label: "Dashboard" },
    { to: "/accounts", icon: <Wallet size={20} />, label: "Cuentas" },
    { to: "/transactions", icon: <ArrowRightLeft size={20} />, label: "Movimientos" },
    { to: "/budget", icon: <PieChart size={20} />, label: "Presupuesto" },
    { to: "/savings", icon: <PiggyBank size={20} />, label: "Ahorro" },
    { to: "/refunds", icon: <CreditCard size={20} />, label: "Deudas" },
    { to: "/projections", icon: <LineChart size={20} />, label: "Proyección" },
    { to: "/advisor", icon: <Bot size={20} />, label: "Aura AI" },
  ];

  if (!session && !isGuest) {
    return <Login onGuestLogin={() => setIsGuest(true)} />;
  }

  return (
    <FinanceContext.Provider value={{
        ...state,
        setChallenges,
        updateLayout,
        addAccount,
        updateAccount,
        deleteAccount,
        addTransaction,
        updateTransaction,
        deleteTransaction,
        addSaving,
        updateSaving,
        deleteSaving,
        addBudget,
        updateBudget,
        deleteBudget,
        addRefund,
        updateRefund,
        deleteRefund,
        mergeRefunds,
        addExtraSaving,
        deleteExtraSaving,
        updateManualContribution,
        getAccountHistoricalBalance,
        getSavingHistoricalBalance,
        getNetWorthHistorical,
        toggleTheme,
        logout
    }}>
      <Router>
        <div className="flex h-screen bg-slate-100 dark:bg-slate-950 transition-colors overflow-hidden">
          <aside className="hidden md:flex flex-col w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 m-4 rounded-[2.5rem] shadow-xl">
             <div className="flex items-center gap-3 mb-10 px-2">
                <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white">
                   <Wallet size={24} />
                </div>
                <h1 className="text-xl font-black text-slate-800 dark:text-white tracking-tighter">Finanzas<span className="text-blue-500">Pro</span></h1>
             </div>

             <nav className="flex-1 space-y-2">
                {navItems.map(item => (
                  <NavLink 
                    key={item.to} 
                    to={item.to} 
                    className={({ isActive }) => `flex items-center gap-3 px-4 py-3 rounded-2xl transition-all font-bold text-sm ${isActive ? 'bg-slate-900 text-white dark:bg-white dark:text-slate-900 shadow-lg' : 'text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 dark:text-slate-400'}`}
                  >
                    {item.icon}
                    {item.label}
                  </NavLink>
                ))}
             </nav>

             <div className="mt-auto space-y-2">
                <button onClick={toggleTheme} className="flex items-center gap-3 px-4 py-3 text-slate-500 dark:text-slate-400 font-bold text-sm hover:bg-slate-100 dark:hover:bg-slate-800 rounded-2xl w-full transition-colors">
                   {state.theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                   {state.theme === 'dark' ? 'Modo Claro' : 'Modo Oscuro'}
                </button>
                <button onClick={logout} className="flex items-center gap-3 px-4 py-3 text-rose-500 font-bold text-sm hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-2xl w-full transition-colors">
                   <LogOut size={20} />
                   Cerrar Sesión
                </button>
             </div>
          </aside>

          <div className="md:hidden fixed top-0 left-0 right-0 h-20 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md z-40 px-6 flex items-center justify-between border-b border-slate-200 dark:border-slate-800">
             <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white">
                   <Wallet size={18} />
                </div>
                <h1 className="text-lg font-black text-slate-800 dark:text-white">Finanzas<span className="text-blue-500">Pro</span></h1>
             </div>
             <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-600 dark:text-slate-300">
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
             </button>
          </div>

          {isMobileMenuOpen && (
             <div className="fixed inset-0 bg-white dark:bg-slate-950 z-30 pt-24 px-6 md:hidden animate-in slide-in-from-top-10">
                <nav className="space-y-2">
                  {navItems.map(item => (
                    <NavLink 
                      key={item.to} 
                      to={item.to} 
                      onClick={() => setIsMobileMenuOpen(false)}
                      className={({ isActive }) => `flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold text-lg ${isActive ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 dark:shadow-none' : 'text-slate-500 dark:text-slate-400'}`}
                    >
                      {item.icon}
                      {item.label}
                    </NavLink>
                  ))}
                  <div className="h-px bg-slate-100 dark:bg-slate-800 my-4" />
                  <button onClick={() => { toggleTheme(); setIsMobileMenuOpen(false); }} className="flex items-center gap-4 px-6 py-4 text-slate-500 dark:text-slate-400 font-bold text-lg w-full">
                     {state.theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                     Cambiar Tema
                  </button>
                  <button onClick={logout} className="flex items-center gap-4 px-6 py-4 text-rose-500 font-bold text-lg w-full">
                     <LogOut size={20} />
                     Salir
                  </button>
                </nav>
             </div>
          )}

          <main className="flex-1 overflow-y-auto p-4 md:p-8 pt-24 md:pt-8 custom-scrollbar relative">
             <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetComponent />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/advisor" element={<AIAdvisor />} />
                <Route path="/projections" element={<WealthProjections />} />
                <Route path="*" element={<Navigate to="/" />} />
             </Routes>
          </main>
        </div>
      </Router>
    </FinanceContext.Provider>
  );
};

