import React, { useState } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  Trash2, 
  Edit2, 
  ShoppingBag, 
  TrendingUp, 
  AlertCircle, 
  Check, 
  X,
  Target
} from 'lucide-react';
import { Budget } from '../types';
import { CATEGORIES, INCOME_CATEGORIES } from '../constants';

const BudgetComponent: React.FC = () => {
  const { budgets, transactions, currentDate, addBudget, updateBudget, deleteBudget } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [editingBudget, setEditingBudget] = useState<Budget | null>(null);
  const [budgetToDelete, setBudgetToDelete] = useState<Budget | null>(null);

  // Form State
  const [category, setCategory] = useState('');
  const [limit, setLimit] = useState<number | ''>('');
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [color, setColor] = useState('#3b82f6');

  const openAdd = () => {
    setCategory('');
    setLimit('');
    setType('expense');
    setColor('#3b82f6');
    setEditingBudget(null);
    setIsAdding(true);
  };

  const openEdit = (b: Budget) => {
    setCategory(b.category);
    setLimit(b.limit);
    setType(b.type);
    setColor(b.color);
    setEditingBudget(b);
    setIsAdding(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (limit === '') return;

    // Default icons based on type for simplicity
    const icon = type === 'expense' ? 'ShoppingBag' : 'TrendingUp';

    if (editingBudget) {
      updateBudget({
        ...editingBudget,
        category,
        limit: Number(limit),
        type,
        color,
        icon
      });
    } else {
      addBudget({
        category,
        limit: Number(limit),
        type,
        color,
        icon
      });
    }
    setIsAdding(false);
    setEditingBudget(null);
  };

  // Helper to calculate spent/earned for a category in current month
  const getCategoryAmount = (cat: string, type: 'income' | 'expense') => {
    return transactions
      .filter(t => t.date.startsWith(currentDate) && t.category === cat)
      .reduce((sum, t) => {
         if (type === 'expense') {
             if (t.type === 'expense') return sum + t.amount;
             if (t.type === 'income' && t.refundId) return sum - t.amount;
             return sum;
         } else {
             if (t.type === 'income') return sum + t.amount;
             return sum;
         }
      }, 0);
  };

  const categoryList = type === 'expense' ? CATEGORIES : INCOME_CATEGORIES;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Presupuesto Mensual</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Planifica tus límites para {currentDate}.</p>
        </div>
        <button 
          onClick={openAdd}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
        >
          <Plus size={18} />
          Nuevo Límite
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {budgets.map(b => {
          const currentAmount = getCategoryAmount(b.category, b.type);
          const percentage = b.limit > 0 ? (currentAmount / b.limit) * 100 : 0;
          const isOver = b.type === 'expense' && currentAmount > b.limit;
          const isMet = b.type === 'income' && currentAmount >= b.limit;
          const statusColor = b.type === 'expense' 
            ? (isOver ? 'text-rose-500' : 'text-slate-500') 
            : (isMet ? 'text-emerald-500' : 'text-slate-500');

          return (
            <div key={b.id} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm group hover:shadow-md transition-all relative overflow-hidden">
               {/* Progress Background for Expense */}
               {b.type === 'expense' && (
                  <div 
                    className="absolute bottom-0 left-0 h-1 bg-blue-500 transition-all duration-1000" 
                    style={{ width: `${Math.min(percentage, 100)}%`, backgroundColor: b.color }}
                  ></div>
               )}

               <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                     <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-md" style={{ backgroundColor: b.color }}>
                        {b.type === 'expense' ? <ShoppingBag size={20} /> : <TrendingUp size={20} />}
                     </div>
                     <div>
                        <h3 className="font-bold text-slate-800 dark:text-white text-lg">{b.category}</h3>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{b.type === 'expense' ? 'Límite de Gasto' : 'Meta de Ingreso'}</p>
                     </div>
                  </div>
                  <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                      <button onClick={() => openEdit(b)} className="p-2 rounded-xl text-slate-400 hover:text-blue-500 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"><Edit2 size={18} /></button>
                      <button onClick={() => setBudgetToDelete(b)} className="p-2 rounded-xl text-slate-400 hover:text-rose-500 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"><Trash2 size={18} /></button>
                  </div>
               </div>

               <div className="space-y-4">
                  <div className="flex items-baseline justify-between">
                     <span className={`text-3xl font-black ${statusColor} dark:${statusColor === 'text-slate-500' ? 'text-white' : statusColor}`}>
                        {currentAmount.toLocaleString()}€
                     </span>
                     <span className="text-sm font-bold text-slate-400">
                        / {b.limit.toLocaleString()}€
                     </span>
                  </div>

                  {b.type === 'expense' ? (
                     <div className="w-full h-3 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                        <div 
                           className={`h-full rounded-full transition-all duration-1000 ${isOver ? 'bg-rose-500' : ''}`}
                           style={{ width: `${Math.min(percentage, 100)}%`, backgroundColor: isOver ? undefined : b.color }}
                        ></div>
                     </div>
                  ) : (
                     <div className="flex items-center gap-2 text-xs font-bold text-slate-500">
                        {isMet ? <Check size={16} className="text-emerald-500" /> : <Target size={16} />}
                        {isMet ? 'Meta Alcanzada' : `${(b.limit - currentAmount).toLocaleString()}€ para la meta`}
                     </div>
                  )}

                  {isOver && (
                     <div className="flex items-center gap-2 text-[10px] font-bold text-rose-500 bg-rose-50 dark:bg-rose-900/20 p-2 rounded-lg">
                        <AlertCircle size={14} /> Excedido en {(currentAmount - b.limit).toLocaleString()}€
                     </div>
                  )}
               </div>
            </div>
          );
        })}
      </div>

      {/* Modal Add/Edit */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800">
               <div className="flex justify-between items-center mb-8">
                  <h3 className="text-2xl font-black text-slate-800 dark:text-white">{editingBudget ? 'Editar Presupuesto' : 'Nuevo Presupuesto'}</h3>
                  <button onClick={() => setIsAdding(false)} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400"><X size={20} /></button>
               </div>

               <form onSubmit={handleSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                     <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-xs font-black rounded-lg transition-all ${type === 'expense' ? 'bg-white dark:bg-slate-700 shadow text-slate-900 dark:text-white' : 'text-slate-400'}`}>GASTO</button>
                     <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-xs font-black rounded-lg transition-all ${type === 'income' ? 'bg-white dark:bg-slate-700 shadow text-slate-900 dark:text-white' : 'text-slate-400'}`}>INGRESO</button>
                  </div>

                  <div>
                     <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Categoría</label>
                     <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" required>
                        <option value="">Selecciona categoría</option>
                        {categoryList.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                     </select>
                  </div>

                  <div>
                     <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Límite / Meta (€)</label>
                     <input type="number" value={limit} onChange={e => setLimit(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-black text-lg outline-none text-slate-900 dark:text-white" placeholder="0" required />
                  </div>

                  <div>
                     <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Color Identificativo</label>
                     <div className="flex gap-2 flex-wrap">
                        {['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1'].map(c => (
                           <button 
                              key={c} 
                              type="button" 
                              onClick={() => setColor(c)} 
                              className={`w-8 h-8 rounded-full border-2 transition-all ${color === c ? 'border-slate-400 scale-110' : 'border-transparent'}`}
                              style={{ backgroundColor: c }}
                           />
                        ))}
                     </div>
                  </div>

                  <button type="submit" className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white font-black rounded-2xl shadow-xl shadow-blue-100 dark:shadow-none transition-all active:scale-95">
                     {editingBudget ? 'GUARDAR CAMBIOS' : 'CREAR PRESUPUESTO'}
                  </button>
               </form>
            </div>
         </div>
      )}

      {/* Delete Confirmation */}
      {budgetToDelete && (
         <div className="fixed inset-0 bg-slate-900/90 z-[60] flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 max-w-sm w-full text-center animate-in zoom-in duration-200">
               <div className="w-16 h-16 bg-rose-50 dark:bg-rose-900/20 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Trash2 size={32} />
               </div>
               <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">¿Eliminar presupuesto?</h3>
               <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">Esta acción no elimina los movimientos, solo la meta establecida.</p>
               <div className="flex gap-3">
                  <button onClick={() => setBudgetToDelete(null)} className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-xl">Cancelar</button>
                  <button onClick={() => { deleteBudget(budgetToDelete.id); setBudgetToDelete(null); }} className="flex-1 py-3 bg-rose-600 text-white font-bold rounded-xl">Eliminar</button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

export default BudgetComponent;
